package com.travelassistant.trip;
import java.util.concurrent.RejectedExecutionException; import org.springframework.beans.factory.annotation.Qualifier; import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor; import org.springframework.stereotype.Component; import org.springframework.transaction.event.*;
@Component public class TripGenerationListener {private final TripGenerationService service;private final ThreadPoolTaskExecutor executor;private final TripDispatchCapacity capacity;public TripGenerationListener(TripGenerationService s,@Qualifier("tripPlanningExecutor")ThreadPoolTaskExecutor e,TripDispatchCapacity c){service=s;executor=e;capacity=c;}
 @TransactionalEventListener(phase=TransactionPhase.AFTER_COMMIT) public void generate(TripGenerationRequested e){try{executor.execute(()->{try{service.process(e.jobId());}finally{capacity.release();}});}catch(RejectedExecutionException rejected){try{service.reject(e.jobId(),"GENERATION_QUEUE_FULL");}finally{capacity.release();}}}}
